import{_ as o,c as e,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"監控排障: 請求日誌分析 | Antigravity-Manager","description":"學習 Antigravity Tools 的 Proxy Monitor 監控排障。透過請求日誌、篩選和詳情還原功能，定位 401/429/5xx 錯誤與流式中斷問題。","frontmatter":{"title":"監控排障: 請求日誌分析 | Antigravity-Manager","sidebarTitle":"請求日誌查錯","subtitle":"監控排障: 請求日誌分析","description":"學習 Antigravity Tools 的 Proxy Monitor 監控排障。透過請求日誌、篩選和詳情還原功能，定位 401/429/5xx 錯誤與流式中斷問題。","tags":["進階","監控","排障","Proxy","日誌"],"prerequisite":["start-proxy-and-first-client","start-first-run-data","advanced-config"],"order":6},"headers":[],"relativePath":"zh-tw/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md","filePath":"zh-tw/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md"}'),i={name:"zh-tw/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md"};function d(l,t,s,n,c,p){return a(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="proxy-monitor-請求日誌、篩選、詳情還原與匯出" tabindex="-1">Proxy Monitor：請求日誌、篩選、詳情還原與匯出 <a class="header-anchor" href="#proxy-monitor-請求日誌、篩選、詳情還原與匯出" aria-label="Permalink to &quot;Proxy Monitor：請求日誌、篩選、詳情還原與匯出&quot;">​</a></h1><p>你已經把本地反代跑起來了，但一旦出現 401/429/500、流式中斷、或者「怎麼突然換了帳號/換了模型」，排障就很容易變成盲猜。</p><p>這節課只講一件事：用 <strong>Proxy Monitor</strong> 把每次呼叫還原成「可覆盤的證據」，讓你知道請求從哪來、打到哪個端點、用了哪個帳號、模型有沒有被映射、以及 Token 消耗大概是多少。</p><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>在 <code>/monitor</code> 頁面打開/暫停錄製，並理解它會不會影響 Token Stats</li><li>用搜尋框、快速篩選、帳號篩選，快速定位一條請求記錄</li><li>在詳情彈窗裡查看並複製 Request/Response 報文，覆盤失敗原因</li><li>知道 Proxy Monitor 的資料落盤位置（<code>proxy_logs.db</code>）與清空行為</li><li>了解目前版本「匯出日誌」的真實能力邊界（GUI vs 後端指令）</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><ul><li>你只看到「呼叫失敗/逾時」，但不知道到底失敗在上游、代理、還是客戶端設定</li><li>你懷疑觸發了模型映射或帳號輪替，但沒有證據鏈</li><li>你想覆盤一條請求的完整 payload（尤其是流式/Thinking），但日誌裡看不到</li></ul><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><ul><li>你要排查：401 鑑權失敗、429 限流、5xx 上游錯誤、流式中斷</li><li>你想確認：某次請求到底用了哪個帳號（<code>X-Account-Email</code>）</li><li>你在做模型路由策略，想驗證「客戶端模型名 -&gt; 實際映射模型名」</li></ul><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前置條件</p><p>Proxy Monitor 記錄的是「反代服務收到的請求」。所以你至少要先跑通：</p><ul><li>反代服務已啟動，並能存取 <code>/healthz</code></li><li>你知道目前反代的 Base URL 和連接埠</li></ul><p>如果還沒跑通，先看 <strong><a href="/docs/opencodedocs/zh-tw/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">啟動本地反代並接入第一個客戶端</a></strong>。</p></div><h2 id="什麼是-proxy-monitor" tabindex="-1">什麼是 Proxy Monitor？ <a class="header-anchor" href="#什麼是-proxy-monitor" aria-label="Permalink to &quot;什麼是 Proxy Monitor？&quot;">​</a></h2><p><strong>Proxy Monitor</strong> 是 Antigravity Tools 內建的「請求日誌看板」。每次請求進到本地反代後，它會記錄時間、路徑、狀態碼、耗時、模型與協定，並盡量從回應裡提取 Token 用量；你還能點開單條記錄查看請求與回應報文，用它來覆盤失敗原因和路由/帳號選擇結果。</p><div class="info custom-block"><p class="custom-block-title">資料落盤位置</p><p>Proxy Monitor 的日誌會寫入資料目錄下的 SQLite：<code>proxy_logs.db</code>。資料目錄怎麼找、怎麼備份，建議先複習 <strong><a href="/docs/opencodedocs/zh-tw/lbjlaq/Antigravity-Manager/start/first-run-data/">首次啟動必懂：資料目錄、日誌、系統托盤與自動啟動</a></strong>。</p></div><h2 id="核心思路-你需要盯住的-6-個欄位" tabindex="-1">核心思路：你需要盯住的 6 個欄位 <a class="header-anchor" href="#核心思路-你需要盯住的-6-個欄位" aria-label="Permalink to &quot;核心思路：你需要盯住的 6 個欄位&quot;">​</a></h2><p>Proxy Monitor 的一條記錄（後端結構體 <code>ProxyRequestLog</code>）裡，最實用的是下面這些欄位：</p><table tabindex="0"><thead><tr><th>欄位</th><th>你用它回答什麼問題</th></tr></thead><tbody><tr><td><code>status</code></td><td>這次請求是成功還是失敗（200-399 vs 其他）</td></tr><tr><td><code>url</code> / <code>method</code></td><td>你到底打到了哪個端點（例如 <code>/v1/messages</code>、<code>/v1/chat/completions</code>）</td></tr><tr><td><code>protocol</code></td><td>這是 OpenAI / Claude(Anthropic) / Gemini 哪套協定</td></tr><tr><td><code>account_email</code></td><td>這次請求最終用了哪個帳號（來自 <code>X-Account-Email</code> 回應標頭）</td></tr><tr><td><code>model</code> / <code>mapped_model</code></td><td>客戶端請求的模型名有沒有被「路由/映射」成另一個模型</td></tr><tr><td><code>input_tokens</code> / <code>output_tokens</code></td><td>這次請求的 Token 用量（能提取到才有）</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">先用「摘要」，需要時再點「詳情」</p><p>列表頁只展示摘要（不帶 request/response body），點開一條記錄才會去後端載入完整詳情，避免列表一次性拉太多大欄位。</p></div><h2 id="跟我做-用一次呼叫跑通「監控閉環」" tabindex="-1">跟我做：用一次呼叫跑通「監控閉環」 <a class="header-anchor" href="#跟我做-用一次呼叫跑通「監控閉環」" aria-label="Permalink to &quot;跟我做：用一次呼叫跑通「監控閉環」&quot;">​</a></h2><h3 id="第-1-步-先製造一條「你確定會出現」的請求" tabindex="-1">第 1 步：先製造一條「你確定會出現」的請求 <a class="header-anchor" href="#第-1-步-先製造一條「你確定會出現」的請求" aria-label="Permalink to &quot;第 1 步：先製造一條「你確定會出現」的請求&quot;">​</a></h3><p><strong>為什麼</strong> Proxy Monitor 只記錄反代服務收到的請求。先用一個最簡單的請求把「有沒有記錄」這件事驗證掉，後面才談篩選和詳情。</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-B8mcU" id="tab-UGXfO_Z" checked><label data-title="macOS/Linux" for="tab-UGXfO_Z">macOS/Linux</label><input type="radio" name="group-B8mcU" id="tab-66Dhtxo"><label data-title="Windows" for="tab-66Dhtxo">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 1) 探活（一定存在的端點）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://127.0.0.1:PORT/healthz&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 2) 再請求一次 models（如果你開啟了鑑權，記得加 header）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://127.0.0.1:PORT/v1/models&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 1) 探活（一定存在的端點）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:PORT/healthz&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 2) 再請求一次 models（如果你開啟了鑑權，記得加 header）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:PORT/v1/models&quot;</span></span></code></pre></div></div></div><p><strong>你應該看到</strong>：終端返回 <code>{&quot;status&quot;:&quot;ok&quot;}</code>（或類似 JSON），以及 <code>/v1/models</code> 的回應（成功或 401 都行）。</p><h3 id="第-2-步-開啟-monitor-頁面並確認「錄製狀態」" tabindex="-1">第 2 步：開啟 Monitor 頁面並確認「錄製狀態」 <a class="header-anchor" href="#第-2-步-開啟-monitor-頁面並確認「錄製狀態」" aria-label="Permalink to &quot;第 2 步：開啟 Monitor 頁面並確認「錄製狀態」&quot;">​</a></h3><p><strong>為什麼</strong> Proxy Monitor 有「錄製/暫停」開關。你需要先確認目前狀態，否則你可能一直在請求，但列表永遠是空的。</p><p>在 Antigravity Tools 裡開啟側邊欄的 <strong>API 監控看板</strong>（路由為 <code>/monitor</code>）。</p><p>頁面頂部會有一個帶圓點的按鈕：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ● 正在錄製   [搜尋框]  [重新整理] [清除]      │</span></span>
<span class="line"><span>└───────────────────────────────────────────┘</span></span></code></pre></div><p>如果你看到的是「已暫停」，點一下切換到「正在錄製」。</p><p><strong>你應該看到</strong>：按鈕狀態變成「正在錄製」；列表裡開始出現剛才的請求記錄。</p><h3 id="第-3-步-用「搜尋-快速篩選」定位一條記錄" tabindex="-1">第 3 步：用「搜尋 + 快速篩選」定位一條記錄 <a class="header-anchor" href="#第-3-步-用「搜尋-快速篩選」定位一條記錄" aria-label="Permalink to &quot;第 3 步：用「搜尋 + 快速篩選」定位一條記錄&quot;">​</a></h3><p><strong>為什麼</strong> 真實排障時，你通常只記得一個片段：路徑裡有 <code>messages</code>，或者狀態碼是 <code>401</code>，或者模型名裡有 <code>gemini</code>。搜尋框就是為這種記憶設計的。</p><p>Proxy Monitor 的搜尋，會把你的輸入當成一個「模糊關鍵字」，在後端用 SQL <code>LIKE</code> 匹配這些欄位：</p><ul><li><code>url</code></li><li><code>method</code></li><li><code>model</code></li><li><code>status</code></li><li><code>account_email</code></li></ul><p>你可以試幾個典型關鍵字：</p><ul><li><code>healthz</code></li><li><code>models</code></li><li><code>401</code>（如果你剛好製造了一個 401）</li></ul><p>也可以點「快速過濾」按鈕：<strong>僅錯誤 / Chat / Gemini / Claude / 繪圖</strong>。</p><p><strong>你應該看到</strong>：列表只剩下你期望的那一類請求。</p><h3 id="第-4-步-點開詳情-還原「請求報文-回應報文」" tabindex="-1">第 4 步：點開詳情，還原「請求報文 + 回應報文」 <a class="header-anchor" href="#第-4-步-點開詳情-還原「請求報文-回應報文」" aria-label="Permalink to &quot;第 4 步：點開詳情，還原「請求報文 + 回應報文」&quot;">​</a></h3><p><strong>為什麼</strong> 列表只夠回答「發生了什麼」。要回答「為什麼」，你通常需要看完整請求/回應 payload。</p><p>點開任意一條記錄，會彈出詳情視窗。你可以重點檢查：</p><ul><li><code>協定</code>（OpenAI/Claude/Gemini）</li><li><code>使用模型</code> 與 <code>映射模型</code></li><li><code>使用帳號</code></li><li><code>Token 消耗 (輸入/輸出)</code></li></ul><p>然後用按鈕複製：</p><ul><li><code>請求報文 (Request)</code></li><li><code>回應報文 (Response)</code></li></ul><p><strong>你應該看到</strong>：詳情裡有兩塊 JSON（或文字）預覽；複製後你可以貼到工單/筆記裡做覆盤。</p><h3 id="第-5-步-需要「從零開始重現」時-清空日誌" tabindex="-1">第 5 步：需要「從零開始重現」時，清空日誌 <a class="header-anchor" href="#第-5-步-需要「從零開始重現」時-清空日誌" aria-label="Permalink to &quot;第 5 步：需要「從零開始重現」時，清空日誌&quot;">​</a></h3><p><strong>為什麼</strong> 排障時最怕「舊資料干擾判斷」。清空後重現一次，成功/失敗會非常清楚。</p><p>點擊頂部的「清除」按鈕，會彈出確認框。</p><div class="danger custom-block"><p class="custom-block-title">這是不可逆操作</p><p>清除會刪除 <code>proxy_logs.db</code> 裡的所有記錄。</p></div><p><strong>你應該看到</strong>：確認後列表清空，統計數字回到 0。</p><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><ul><li>[ ] 你能在 <code>/monitor</code> 看到自己剛發出的 <code>/healthz</code> 或 <code>/v1/models</code> 記錄</li><li>[ ] 你能用搜尋框把某條記錄篩出來（例如輸入 <code>healthz</code>）</li><li>[ ] 你能點開一條記錄看到請求/回應報文，並複製出來</li><li>[ ] 你知道清空日誌會直接刪除所有歷史記錄</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><table tabindex="0"><thead><tr><th>場景</th><th>你可能會怎麼理解（❌）</th><th>實際表現（✓）</th></tr></thead><tbody><tr><td>&quot;已暫停&quot;= 完全沒有監控開銷</td><td>以為暫停後請求就不會被解析</td><td>暫停只影響「是否寫入 Proxy Monitor 日誌」。但請求/回應解析（包括流式資料的 SSE 解析）仍會發生，只是解析後的資料不被儲存。Token Stats 也仍會記錄（無論監控是否啟用）。</td></tr><tr><td>二進位/大封包日誌為空</td><td>以為是監控壞了</td><td>二進位請求/回應會顯示為 <code>[Binary Request Data]</code> / <code>[Binary Response Data]</code>。回應體超過 100MB 會標記為 <code>[Response too large (&gt;100MB)]</code>；請求體超過限制則不記錄。</td></tr><tr><td>想用 Monitor 找到「誰發起了請求」</td><td>以為能追溯到客戶端程序</td><td>Monitor 記錄的是 HTTP 層資訊（方法/路徑/模型/帳號），不包含「呼叫方程序名」。你需要結合客戶端自身日誌或系統網路抓包定位來源。</td></tr><tr><td>啟用監控時 Token Stats 資料異常</td><td>以為是統計錯誤</td><td>監控啟用時，Token Stats 可能被記錄兩次（一次在監控函式開頭，一次在非同步寫入資料庫時）。這是目前版本的原始碼行為。</td></tr></tbody></table><h2 id="匯出與長期留存-先說清楚能力邊界" tabindex="-1">匯出與長期留存：先說清楚能力邊界 <a class="header-anchor" href="#匯出與長期留存-先說清楚能力邊界" aria-label="Permalink to &quot;匯出與長期留存：先說清楚能力邊界&quot;">​</a></h2><h3 id="_1-gui-裡目前能做什麼" tabindex="-1">1) GUI 裡目前能做什麼 <a class="header-anchor" href="#_1-gui-裡目前能做什麼" aria-label="Permalink to &quot;1) GUI 裡目前能做什麼&quot;">​</a></h3><p>在目前版本的 Monitor UI（<code>ProxyMonitor.tsx</code>）裡，你可以：</p><ul><li>搜尋/篩選/分頁瀏覽</li><li>點開詳情查看與複製 payload</li><li>清空全部日誌</li></ul><p>但 <strong>沒有發現「匯出按鈕」</strong>（原始碼裡未看到相關 UI）。</p><h3 id="_2-後端已經有什麼匯出能力-適合二次開發" tabindex="-1">2) 後端已經有什麼匯出能力（適合二次開發） <a class="header-anchor" href="#_2-後端已經有什麼匯出能力-適合二次開發" aria-label="Permalink to &quot;2) 後端已經有什麼匯出能力（適合二次開發）&quot;">​</a></h3><p>後端 Tauri 指令提供了兩種匯出方式：</p><ul><li><code>export_proxy_logs(file_path)</code>：把資料庫裡「全部日誌」匯出為 JSON 檔案</li><li><code>export_proxy_logs_json(file_path, json_data)</code>：把你傳入的 JSON 陣列美化後寫入檔案（要求輸入必須是陣列格式）</li></ul><p>如果你要二次開發 GUI，或者寫一個自己的呼叫腳本，可以直接複用這些指令。</p><h3 id="_3-最樸素的「匯出」-直接備份-proxy-logs-db" tabindex="-1">3) 最樸素的「匯出」：直接備份 <code>proxy_logs.db</code> <a class="header-anchor" href="#_3-最樸素的「匯出」-直接備份-proxy-logs-db" aria-label="Permalink to &quot;3) 最樸素的「匯出」：直接備份 \`proxy_logs.db\`&quot;">​</a></h3><p>因為 Proxy Monitor 本質是 SQLite，你也可以把 <code>proxy_logs.db</code> 當成「排障證據包」一起備份（例如連同 <code>token_stats.db</code>）。資料目錄位置見 <strong><a href="/docs/opencodedocs/zh-tw/lbjlaq/Antigravity-Manager/start/first-run-data/">首次啟動必懂</a></strong>。</p><h2 id="推薦閱讀" tabindex="-1">推薦閱讀 <a class="header-anchor" href="#推薦閱讀" aria-label="Permalink to &quot;推薦閱讀&quot;">​</a></h2><ul><li>想弄清模型映射：<strong><a href="/docs/opencodedocs/zh-tw/lbjlaq/Antigravity-Manager/advanced/model-router/">模型路由：自定義映射、萬用字元優先順序與預設策略</a></strong></li><li>想排查鑑權問題：<strong><a href="/docs/opencodedocs/zh-tw/lbjlaq/Antigravity-Manager/faq/auth-401/">401/鑑權失敗：auth_mode、Header 相容與客戶端設定清單</a></strong></li><li>想把 Monitor 與成本統計結合：下一節會講 Token Stats（<code>token_stats.db</code>）</li></ul><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><ul><li>Proxy Monitor 的價值是「可覆盤」：記錄狀態碼/路徑/協定/帳號/模型映射/Token 用量，並提供請求詳情</li><li>搜尋與快速篩選是排障入口：先縮小範圍，再點詳情看 payload</li><li>清空日誌是不可逆操作；匯出目前更偏向「二次開發能力」和「備份資料庫檔案」</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="/docs/opencodedocs/zh-tw/lbjlaq/Antigravity-Manager/advanced/token-stats/">Token Stats：成本視角的統計口徑與圖表解讀</a></strong>，把「感覺貴」變成可量化的最佳化。</p></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>Monitor 頁面入口（掛載 ProxyMonitor）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Monitor.tsx#L1-L12" target="_blank" rel="noreferrer"><code>src/pages/Monitor.tsx</code></a></td><td>1-12</td></tr><tr><td>Monitor UI：表格/篩選/詳情彈窗</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L13-L713" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>13-713</td></tr><tr><td>UI：讀取設定並同步 enable_logging</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L174-L243" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>174-243</td></tr><tr><td>UI：切換錄製（寫入 config + set_proxy_monitor_enabled）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L254-L267" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>254-267</td></tr><tr><td>UI：即時事件監聽（proxy://request）與去重</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L273-L355" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>273-355</td></tr><tr><td>UI：清空日誌（clear_proxy_logs）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L389-L403" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>389-403</td></tr><tr><td>UI：載入單條詳情（get_proxy_log_detail）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L505-L519" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>505-519</td></tr><tr><td>監控中介軟體：抓取請求/回應、解析 token、寫入 monitor</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L13-L337" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>13-337</td></tr><tr><td>ProxyMonitor：enabled 開關、寫 DB、發事件</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/monitor.rs#L33-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/monitor.rs</code></a></td><td>33-194</td></tr><tr><td>伺服器端掛載監控中介軟體（layer）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L183-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>183-194</td></tr><tr><td>Tauri 指令：get/count/filter/detail/clear/export</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/proxy.rs#L180-L314" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/proxy.rs</code></a></td><td>180-314</td></tr><tr><td>SQLite：proxy_logs.db 路徑、表結構與篩選 SQL</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/proxy_db.rs#L1-L416" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/proxy_db.rs</code></a></td><td>1-416</td></tr><tr><td>監控設計說明（可能與實作有差異，以原始碼為準）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-monitor-technical.md#L1-L53" target="_blank" rel="noreferrer"><code>docs/proxy-monitor-technical.md</code></a></td><td>1-53</td></tr></tbody></table><p><strong>關鍵常量</strong>：</p><ul><li><code>MAX_REQUEST_LOG_SIZE = 100 * 1024 * 1024</code>：監控中介軟體最大可讀取的請求體（超過會讀取失敗）</li><li><code>MAX_RESPONSE_LOG_SIZE = 100 * 1024 * 1024</code>：監控中介軟體最大可讀取的回應體（用於圖片等大回應）</li></ul><p><strong>關鍵函式/指令</strong>：</p><ul><li><code>monitor_middleware(...)</code>：在 HTTP 層採集請求與回應，並呼叫 <code>monitor.log_request(...)</code></li><li><code>ProxyMonitor::log_request(...)</code>：寫入記憶體 + SQLite，並透過 <code>proxy://request</code> 事件推送摘要</li><li><code>get_proxy_logs_count_filtered(filter, errors_only)</code> / <code>get_proxy_logs_filtered(...)</code>：列表頁篩選與分頁</li><li><code>get_proxy_log_detail(log_id)</code>：載入單條日誌的完整 request/response body</li><li><code>export_proxy_logs(file_path)</code>：匯出全量日誌到 JSON 檔案（目前 UI 未暴露按鈕）</li></ul></details>`,74)])])}const u=o(i,[["render",d]]);export{g as __pageData,u as default};
